import{_ as t,o as e,c as r,a3 as s}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"10A. Consultation About Changes To Rosters Or Hours Of Work","description":"","frontmatter":{"title":"10A. Consultation About Changes To Rosters Or Hours Of Work","eba":"Doctors in Training 2022-2026","topics":["hours","rosters","consultation"]},"headers":[],"relativePath":"ebas/doctors-in-training/consultation-disputes/10A-consultation-about-changes-to-rosters-or-hours-of-work.md","filePath":"ebas/doctors-in-training/consultation-disputes/10A-consultation-about-changes-to-rosters-or-hours-of-work.md"}'),n={name:"ebas/doctors-in-training/consultation-disputes/10A-consultation-about-changes-to-rosters-or-hours-of-work.md"};function a(i,o,c,h,u,p){return e(),r("div",null,[...o[0]||(o[0]=[s('<h1 id="_10a-consultation-about-changes-to-rosters-or-hours-of-work" tabindex="-1">10A. Consultation About Changes To Rosters Or Hours Of Work <a class="header-anchor" href="#_10a-consultation-about-changes-to-rosters-or-hours-of-work" aria-label="Permalink to &quot;10A. Consultation About Changes To Rosters Or Hours Of Work&quot;">​</a></h1><p>This clause 10A applies where a change to regular rosters or ordinary hours of work (which may impact upon a Doctor, particularly in relation to their family and caring responsibilities) does not constitute ‘Major Change in accordance with subclause 10.2(c)).</p><p>10A.1. Where a Health Service proposes to change a Doctor’s regular roster or ordinary hours of work, the Health Service must consult with the Doctor or Doctors affected and their representatives, if any, about the proposed change.</p><p><strong>10A.2</strong> The Health Service must:</p><p><strong>(a)</strong> consider health and safety impacts including fatigue;</p><p><strong>(b)</strong> provide to the Doctor or Doctors affected and their representatives, if any, information about the proposed change (for example, information about the nature of the change to the Doctor’s regular roster or ordinary hours of work and when that change is proposed to commence);</p><p><strong>(c)</strong> invite the Doctor or Doctors affected and their representatives, if any, to give their views about the impact of the proposed change (including any impact in relation to their family or caring responsibilities); and</p><p><strong>(d)</strong> give consideration to any views about the impact of the proposed change that is given by the Doctor or Doctors concerned and/or their representatives.</p><p><strong>10A.3</strong> The requirement to consult under this clause 10A does not apply to a Doctor where the change to a Doctor’s regular roster or ordinary hours of work is as a consequence of that Doctor’s has irregular, sporadic or unpredictable working hours, self-rostering or, where permitted, a rotating roster.</p><p><strong>10A.4</strong> The provisions of this clause 10A are to be read in conjunction with the terms of the engagement between the Health Service and Doctor, and other Agreement provisions concerning the scheduling of work and notice requirements.</p><p>Plain language terms: roster consultation.</p>',11)])])}const d=t(n,[["render",a]]);export{g as __pageData,d as default};
